// Normalize inputs. snapshot_id may arrive as a string OR an array (the add-node
// in GDcompletionSnapshotWorkflow returns it wrapped in a one-element array).
const snapshotIdRaw = {{workflowparams:snapshot_id}};
const docId = {{workflowparams:doc_id}} || "";
const gdNo = {{workflowparams:gd_no}} || "";
const plantId = {{workflowparams:plant_id}} || "";
const organizationId = {{workflowparams:organization_id}} || "";
const tableData = {{workflowparams:tableData}} || [];

let snapshotId = "";
if (Array.isArray(snapshotIdRaw)) {
  snapshotId = snapshotIdRaw[0] || "";
} else {
  snapshotId = snapshotIdRaw || "";
}

// Extract material ids from tableData for item master fetch.
const materialIdsSet = new Set();
for (const item of tableData) {
  if (item && item.material_id) materialIdsSet.add(item.material_id);
}
const materialIds = [...materialIdsSet];

return {
  snapshotId,
  docId,
  gdNo,
  plantId,
  organizationId,
  materialIds,
  hasSnapshotId: snapshotId ? 1 : 0,
  hasMaterials: materialIds.length > 0 ? 1 : 0,
};

// get-node returns single object when count=1, array when count>1, null when count=0.
const raw = {{node:get_node_inSnapshot.data}};
const count = {{node:get_node_inSnapshot.data.count}} || 0;

let snapshot = null;
if (raw && raw.data) {
  // get-node may wrap result; try to unwrap
  snapshot = Array.isArray(raw.data) ? raw.data[0] : raw.data;
} else if (raw && !Array.isArray(raw) && raw.id) {
  snapshot = raw;
} else if (Array.isArray(raw) && raw.length > 0) {
  snapshot = raw[0];
}

if (!snapshot || !snapshot.id || snapshot.snapshot_status !== "Active") {
  return {
    snapshotFound: 0,
    snapshotStatus: snapshot ? snapshot.snapshot_status : "",
    pre_so_lines: [],
    pre_pending_state: [],
    pre_on_reserved_gd_ids: [],
    pre_picking_records: [],
    pre_pp_headers: [],
    pre_hu_state: { hus: [], lines: [] },
    pp_restamp_map: {},
    pendingIds: [],
    pickingRecordIds: [],
    ppHeaderIds: [],
    huIds: [],
    huLineIds: [],
    hasPendings: 0,
    hasPickingRecords: 0,
    hasPpHeaders: 0,
    hasHus: 0,
    hasHuLines: 0,
  };
}

const parse = (raw, def) => {
  if (raw === null || raw === undefined || raw === "") return def;
  if (typeof raw === "string") {
    try { return JSON.parse(raw); } catch (e) { return def; }
  }
  return raw;
};

const pre_so_lines = parse(snapshot.pre_so_lines, []);
const pre_pending_state = parse(snapshot.pre_pending_state, []);
const pre_on_reserved_gd_ids = parse(snapshot.pre_on_reserved_gd_ids, []);
const pre_picking_records = parse(snapshot.pre_picking_records, []);
const pre_pp_headers = parse(snapshot.pre_pp_headers, []);
const pre_hu_state = parse(snapshot.pre_hu_state, { hus: [], lines: [] });
const pp_restamp_map = parse(snapshot.pp_restamp_map, {});

const pendingIds = pre_pending_state.map((p) => p.id);
const pickingRecordIds = pre_picking_records.map((r) => r.id);
const ppHeaderIds = pre_pp_headers.map((h) => h.id);
const huIds = (pre_hu_state.hus || []).map((h) => h.id);
const huLineIds = (pre_hu_state.lines || []).map((l) => l.id);

return {
  snapshotFound: 1,
  snapshotStatus: "Active",
  snapshotRecordId: snapshot.id,
  pre_so_lines,
  pre_pending_state,
  pre_on_reserved_gd_ids,
  pre_picking_records,
  pre_pp_headers,
  pre_hu_state,
  pp_restamp_map,
  pendingIds,
  pickingRecordIds,
  ppHeaderIds,
  huIds,
  huLineIds,
  hasPendings: pendingIds.length > 0 ? 1 : 0,
  hasPickingRecords: pickingRecordIds.length > 0 ? 1 : 0,
  hasPpHeaders: ppHeaderIds.length > 0 ? 1 : 0,
  hasHus: huIds.length > 0 ? 1 : 0,
  hasHuLines: huLineIds.length > 0 ? 1 : 0,
};

// Inputs: snapshot parsed data + current state of all touched records.
const snap = {{node:code_node_inParseSnap.data}};
const currentReserved = {{node:search_node_inCurReserved.data.data}} || [];
const currentPending = {{node:search_node_inCurPending.data.data}} || [];
const currentPicking = {{node:search_node_inCurPicking.data.data}} || [];
const currentPpHeaders = {{node:search_node_inCurPpHdr.data.data}} || [];
const currentHus = {{node:search_node_inCurHu.data.data}} || [];
const currentHuLines = {{node:search_node_inCurHuLn.data.data}} || [];
const itemsData = {{node:search_node_inItems.data.data}} || [];
const tableData = {{workflowparams:tableData}} || [];
const docId = {{node:code_node_inExtract.data.docId}} || "";

// Build item master lookup with the subset of fields ADD_INVENTORY_NEW needs.
const filterItemData = (it) => {
  if (!it) return null;
  return {
    stock_control: it.stock_control,
    based_uom: it.based_uom,
    table_uom_conversion: it.table_uom_conversion,
    material_costing_method: it.material_costing_method,
    purchase_unit_price: it.purchase_unit_price,
    item_batch_management: it.item_batch_management,
    material_code: it.material_code,
    material_name: it.material_name,
    material_desc: it.material_desc,
  };
};
const itemDataMap = {};
for (const it of itemsData) {
  if (it && it.id) itemDataMap[it.id] = filterItemData(it);
}

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const asArr = (v) => (Array.isArray(v) ? v : (v ? [v] : []));

const pre_pending_state = asArr(snap.pre_pending_state);
const pre_on_reserved_gd_ids = asArr(snap.pre_on_reserved_gd_ids);
const pre_picking_records = asArr(snap.pre_picking_records);
const pre_pp_headers = asArr(snap.pre_pp_headers);
const pre_hu_state = snap.pre_hu_state || { hus: [], lines: [] };
const pp_restamp_map = snap.pp_restamp_map || {};

// ============ CONFLICT DETECTION ============
const conflicts = [];

const preReservedIdSet = new Set(pre_on_reserved_gd_ids.map(String));
const currentReservedById = new Map();
for (const r of currentReserved) currentReservedById.set(String(r.id), r);

// 1. Identify fragments = current ids NOT in pre set
const fragmentIds = [];
for (const r of currentReserved) {
  if (!preReservedIdSet.has(String(r.id))) fragmentIds.push(r.id);
}

// 2. Fragments must still be in expected post-completion state.
// Completion creates them as Cancelled (GD-source fragments) or Pending (SO/Production remainders),
// always with delivered_qty=0. If anything else, another process touched them — refuse.
for (const fid of fragmentIds) {
  const r = currentReservedById.get(String(fid));
  if (!r) continue;
  const okStatus = r.status === "Cancelled" || r.status === "Pending";
  const okDelivered = roundQty(r.delivered_qty) === 0;
  if (!okStatus || !okDelivered) {
    conflicts.push({
      type: "fragment_touched",
      id: r.id,
      message: "Fragment record " + r.id + " was modified post-completion (status=" + r.status + ", delivered_qty=" + r.delivered_qty + ")",
    });
  }
}

// 3. PP restamp conflict: restamped records must currently be doc_type=Good Delivery
// targeting our GD. If reshaped further by another process, refuse.
for (const restampId of Object.keys(pp_restamp_map)) {
  const r = currentReservedById.get(String(restampId));
  if (!r) {
    conflicts.push({
      type: "pp_restamp_missing",
      id: restampId,
      message: "PP-restamped record " + restampId + " not found at revert time",
    });
    continue;
  }
  if (r.doc_type !== "Good Delivery" || String(r.target_gd_id) !== String(docId)) {
    conflicts.push({
      type: "pp_restamp_drift",
      id: restampId,
      message: "PP-restamped record " + restampId + " was re-modified (doc_type=" + r.doc_type + ", target_gd_id=" + r.target_gd_id + ")",
    });
  }
}

// 4. Pending underflow: if current Pending.open_qty < snapshot.open_qty,
// another process consumed from it — we cannot safely restore.
const currentPendingById = new Map();
for (const p of currentPending) currentPendingById.set(String(p.id), p);
for (const pre of pre_pending_state) {
  const cur = currentPendingById.get(String(pre.id));
  if (!cur) {
    conflicts.push({
      type: "pending_missing",
      id: pre.id,
      message: "Pending record " + pre.id + " not found at revert time",
    });
    continue;
  }
  if (roundQty(cur.open_qty) < roundQty(pre.open_qty)) {
    conflicts.push({
      type: "pending_consumed",
      id: pre.id,
      message: "Pending record " + pre.id + " consumed by another process (current.open_qty=" + cur.open_qty + " < snapshot.open_qty=" + pre.open_qty + ")",
    });
  }
}

// 5. HU missing
const currentHuById = new Map();
for (const h of currentHus) currentHuById.set(String(h.id), h);
for (const preHu of (pre_hu_state.hus || [])) {
  if (!currentHuById.has(String(preHu.id))) {
    conflicts.push({
      type: "hu_missing",
      id: preHu.id,
      message: "HU " + preHu.id + " not found at revert time",
    });
  }
}

// 6. Picking record drift: current.delivered_qty should be >= snapshot.delivered_qty
// (completion only adds; if current is less, something subtracted post-completion).
const currentPickingById = new Map();
for (const p of currentPicking) currentPickingById.set(String(p.id), p);
for (const pre of pre_picking_records) {
  const cur = currentPickingById.get(String(pre.id));
  if (!cur) {
    conflicts.push({
      type: "picking_record_missing",
      id: pre.id,
      message: "Picking record " + pre.id + " not found at revert time",
    });
    continue;
  }
  if (roundQty(cur.delivered_qty) < roundQty(pre.delivered_qty)) {
    conflicts.push({
      type: "picking_record_drift",
      id: pre.id,
      message: "Picking record " + pre.id + " delivered_qty decreased since snapshot (current=" + cur.delivered_qty + " < snapshot=" + pre.delivered_qty + ")",
    });
  }
}

if (conflicts.length > 0) {
  return {
    hasConflicts: 1,
    conflictCount: conflicts.length,
    conflicts,
    reservedUpdates: [],
    fragmentSoftDeletes: [],
    pendingRestores: [],
    pickingRecUpdates: [],
    pickingHdrUpdates: [],
    huUpdates: [],
    inventoryMovements: [],
    hasReservedUpdates: 0,
    hasFragments: 0,
    hasPendingRestores: 0,
    hasPickingRecUpdates: 0,
    hasPickingHdrUpdates: 0,
    hasHuUpdates: 0,
    hasInventoryMovements: 0,
  };
}

// ============ BUILD REVERSE BATCHES ============

// 1. Reserved updates: flip Delivered → Allocated. Restore PP restamp linkage if applicable.
// Also emit an inventory ADD movement (qty back to Reserved bucket) for each.
const reservedUpdates = [];
const inventoryMovements = [];
for (const r of currentReserved) {
  if (!preReservedIdSet.has(String(r.id))) continue; // skip fragments
  if (r.status !== "Delivered") continue;

  const deliveredQty = roundQty(r.delivered_qty);
  // Always include doc-identity fields in the update payload, defaulting to the
  // current record's values. The bulk update-node ALWAYS sends these props
  // (its props.list is static); missing array fields resolve to null and would
  // wipe doc_type/doc_id/doc_no/doc_line_id/target_gd_id on Good Delivery
  // records that aren't PP-restamped. For non-PP records, completion didn't
  // touch these fields, so echoing r's values restores them correctly.
  const update = {
    id: r.id,
    status: "Allocated",
    reserved_qty: deliveredQty,
    open_qty: deliveredQty,
    delivered_qty: 0,
    doc_type: r.doc_type,
    doc_id: r.doc_id,
    doc_no: r.doc_no,
    doc_line_id: r.doc_line_id,
    target_gd_id: r.target_gd_id,
  };

  // For PP-restamped records, override with the pre-completion PP linkage
  // captured in pp_restamp_map (completion had overwritten these with GD's identity).
  const restampOrig = pp_restamp_map[String(r.id)];
  if (restampOrig) {
    update.doc_type = restampOrig.doc_type;
    update.doc_id = restampOrig.doc_id;
    update.doc_no = restampOrig.doc_no;
    update.doc_line_id = restampOrig.doc_line_id;
    update.target_gd_id = restampOrig.target_gd_id;
  }

  reservedUpdates.push(update);

  // Build the inverse stock movement: ADD to Reserved bucket at same bin/batch/HU.
  // Completion emitted SUBTRACT_INVENTORY_NEW with inventory_category=Reserved when
  // flipping this record from Allocated → Delivered, so we reverse with ADD.
  if (deliveredQty > 0) {
    inventoryMovements.push({
      material_id: String(r.material_id),
      quantity: deliveredQty,
      material_uom: r.item_uom != null ? String(r.item_uom) : "",
      location_id: r.bin_location != null ? String(r.bin_location) : "",
      batch_id: r.batch_id != null ? String(r.batch_id) : null,
      handling_unit_id: r.handling_unit_id != null ? String(r.handling_unit_id) : null,
      inventory_category: "Reserved",
      parent_no: r.parent_no || "",
      itemData: itemDataMap[String(r.material_id)] || null,
      index: inventoryMovements.length,
    });
  }
}

// 2. Fragment soft-deletes
const fragmentSoftDeletes = fragmentIds.map((id) => ({
  id,
  is_deleted: 1,
  status: "Cancelled",
  open_qty: 0,
}));

// 3. Pending restores: overwrite current with snapshot values
const pendingRestores = pre_pending_state.map((pre) => ({
  id: pre.id,
  reserved_qty: roundQty(pre.reserved_qty),
  open_qty: roundQty(pre.open_qty),
}));

// 4. Picking record reverse: restore reserved_qty + delivered_qty to snapshot baseline.
// We're conservative — overwrite to snapshot, even if completion's delta isn't isolated.
// Conflict gate above already verified no other process delivered against these.
const pickingRecUpdates = pre_picking_records.map((pre) => ({
  id: pre.id,
  reserved_qty: roundQty(pre.reserved_qty),
  delivered_qty: roundQty(pre.delivered_qty),
}));

// 5. Picking header reverse: restore delivery_status to snapshot
const pickingHdrUpdates = pre_pp_headers.map((pre) => ({
  id: pre.id,
  delivery_status: pre.delivery_status,
}));

// 6. HU updates: re-increment HU.total_quantity and item_handling_unit.quantity by gd_quantity.
// Source of truth = tableData's temp_qty_data (what completion decremented).
const huUpdatesMap = new Map();
for (const item of tableData) {
  if (!item.material_id) continue;
  let temps = [];
  try {
    temps = typeof item.temp_qty_data === "string" ? JSON.parse(item.temp_qty_data) : (item.temp_qty_data || []);
  } catch (e) {}
  for (const t of temps) {
    if (!t.handling_unit_id) continue;
    const qty = roundQty(t.gd_quantity || 0);
    if (qty <= 0) continue;
    const key = t.handling_unit_id + "|" + item.material_id + "|" + (t.batch_id || "");
    huUpdatesMap.set(key, roundQty((huUpdatesMap.get(key) || 0) + qty));
  }
}
const huUpdates = [];
for (const [key, qty] of huUpdatesMap) {
  const [handling_unit_id, material_id, batch_id_raw] = key.split("|");
  huUpdates.push({
    handling_unit_id,
    material_id,
    batch_id: batch_id_raw || null,
    increment_quantity: qty,
  });
}

return {
  hasConflicts: 0,
  conflictCount: 0,
  conflicts: [],
  reservedUpdates,
  fragmentSoftDeletes,
  pendingRestores,
  pickingRecUpdates,
  pickingHdrUpdates,
  huUpdates,
  inventoryMovements,
  hasReservedUpdates: reservedUpdates.length > 0 ? 1 : 0,
  hasFragments: fragmentSoftDeletes.length > 0 ? 1 : 0,
  hasPendingRestores: pendingRestores.length > 0 ? 1 : 0,
  hasPickingRecUpdates: pickingRecUpdates.length > 0 ? 1 : 0,
  hasPickingHdrUpdates: pickingHdrUpdates.length > 0 ? 1 : 0,
  hasHuUpdates: huUpdates.length > 0 ? 1 : 0,
  hasInventoryMovements: inventoryMovements.length > 0 ? 1 : 0,
};
